#============ Task:Checking Username Validation ===============def Isvalid():    name = input("Enter a valid Username: ")    if len(name) >= 6:        if name[0].isalpha():            if " " not in name:                print("Valid Username")            else:                print("Username should not contain spaces.")                Isvalid()        else:            print("First character must be a letter.")            Isvalid()    else:        print("Username must contain at least 6 characters.")        Isvalid()print("============ Task:Checking Username Validation ===============")print("\nPassword must contain:\n* At least 6 characters\n* No spaces\n* First character must be a letter.\n")Isvalid()#============ Task:Checking Password Strength ===============def Isstrong():    lower=0    digit=0        password=input(str("Enter a strong password: "))    if len(password)>=8:        if password[0].isupper():            for x in password:                if x.islower():                    lower=lower+1                if x.isdigit():                    digit=digit+1            if lower>=1:                if digit>=1:                  print("Valid Password")                else:                  print("password must contain atleast one digit")                  Isstrong()            else:                  print("password must contain atleast one lower case character")                  Isstrong()                      else:            print("First character should be in upper case")            Isstrong()          else:        print("Password must contain more than 8 characters")          Isstrong()print("\nPassword must contain:\n*At least 8 characters\n*First character must be in upper case\n*Must contain atleast one digit\n*Must contain one lower case")print("\n====== Password Strength Checker =========\n")Isstrong()#============ Task:Word Analyzer ===============def Analyzer(): characters=0 words=1 vowels=0 digits=0 consonants=0 sentence=input(str("Enter the string you want to analyze: ")) for x in sentence:  if x!=" ":    characters=characters+1   if x==" ":    words=words+1  if x=='a' or x=='e' or x=='i' or x=='o' or x=='u':   vowels=vowels+1  else:   if x!=" ":    consonants=consonants+1  if x.isdigit():    digits=digits+1 print("* Number of words: ",words) print("* Number of characters: ",characters) print("* Number of vowels: ",vowels) print("* Number of consonants: ",consonants) print("* Number of digits: ",digits)  print("============ Word Analyzer ===============\n")Analyzer()#============ Task:Student Grade Manager ===============import osdef Grading():    listname=[]  listmarks=[]  listgrade=[]  students=int (input("Enter the number of students: "))     for x in range(students):      name=input(f"Enter the name of {x+1} student: ")      listname.append(name)      marks=int(input(f"Enter marks of {x+1} student: "))      listmarks.append(marks)      if marks>=90:          listgrade.append('A')      elif marks>=80:          listgrade.append('B')      elif marks>=70:          listgrade.append('C')      elif marks>=50:          listgrade.append('D')      else:          listgrade.append('Fail')  os.system("cls")  print("====== Students Record =======\n")  for x in range(students):      print("* ",listname[x],":",listmarks[x],"->",listgrade[x])      Grading()